    a = list(map(int, sys.stdin.readline().split()))

    def get_max(x):
        return a[x]

    def get_min(x):
        return a[x]

    def get_sum(x):
        return a[x]

    def update_max(x, v):
        a[x] = max(a[x], v)

    def update_min(x, v):
        a[x] = min(a[x], v)

    def update_sum(x, v):
        a[x] += v

    def merge(l, m, r):
        for i in range(m, l-1, -1):
            update_max(i, get_max(m))
        for i in range(m, l-1, -1):
            update_min(i, get_min(m))
        for i in range(r, m, 1):
            update_sum(i, get_sum(m))
        for i in range(m, r+1, 1):
            update_min(i, get_min(l-1))
            update_max(i, get_max(r))
        for i in range(m, r+1, 1):
            update_sum(i, get_sum(l-1))

    def build(st, l, r):
        if l == r:
            return
        m = (l + r) // 2
        build(st, l, m)
        build(st, m+1, r)
        merge(st, m, r)

    def query(st, l, r, L, R, k):
        if L <= l and r <= R:
            return get_sum(r) - get_sum(l-1)
        elif r < L or R < l:
            return 0
        else:
            m = (l + r) // 2
            return query(st, l, m, L, R, k) + query(st, m+1, r, L, R, k)

    def update(st, l, r, i, v):
        if l == r:
            update_sum(i, v)
            return
        m = (l + r) // 2
        if i <= m:
            update(st, l, m, i, v)
        else:
            update(st, m+1, r, i, v)
        merge(st, m, r)

    st = 4*n+1
    build(st, 0, n-1)
    ans = 0
    for i in range(n):
        l, r = 0, i
        while l <= r:
            m = (l + r) // 2
            if query(st, 0, n-1, m, i, st) <= s:
                l = m + 1
            else:
                r = m - 1
        if query(st, 0, n-1, 0, i, st) <= s:
            ans += 1
        update(st, 0, n-1, i, -a[i])
        l, r = i+1, n-1
