import sys

N, S, R = map(int, input().split())
A = list(map(int, input().split()))

prefix_sum = [0]
for a in A:
    prefix_sum.append(prefix_sum[-1] + a)

def count_blocks(i, j):
    total = prefix_sum[j + 1] - prefix_sum[i]
    if total > S:
        return 0
    min_val = min(prefix_sum[i:j + 1])
    max_val = max(prefix_sum[i:j + 1])
    gap = max_val - min_val
    if gap > R:
        return 0
    return j - i + 1

def binary_search(l, r):
    while l < r:
        m = (l + r) // 2
        total_blocks = 0
        for i in range(len(A) - m):
            total_blocks += count_blocks(i, i + m - 1)
        if total_blocks >= m:
            r = m
        else:
            l = m + 1
    return l

def solve():
    ans = 0
    for i in range(1, len(A) + 1):
        ans += count_blocks(0, i - 1)
    for i in range(1, len(A) + 1):
        m = binary_search(1, i)
        ans += count_blocks(0, i - 1) - count_blocks(0, i - m - 1)
    return ans

